import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface RequestSummary {
  totalRequests: number;
  averageLatency: number;
  errorRate: number;
}

interface ErrorRateHistory {
  day: string;
  errorRate: number;
}

interface ApiUsageData {
  requestSummary: RequestSummary;
  errorRateHistory: ErrorRateHistory[];
}

export default function Widget() {
  const apiUsageData = response.data as ApiUsageData;
  const { requestSummary, errorRateHistory } = apiUsageData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#B0BEC5', mb: 0.5 }}>
              API Monitor
            </Typography>
            <Typography variant="h6" sx={{ color: '#FF5722', fontWeight: 600 }}>
              Total Requests: {requestSummary.totalRequests.toLocaleString()}
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Avg Latency: {requestSummary.averageLatency} ms
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Error Rate: {requestSummary.errorRate.toFixed(2)}%
            </Typography>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: errorRateHistory.map(d => d.errorRate),
                color: '#03A9F4',
              },
            ]}
            xAxis={[
              {
                data: errorRateHistory.map(d => d.day),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#90A4AE',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
